class Solution:
    def findMinMoves(self, machines: List[int]) -> int:
        total = sum(machines)
        n = len(machines)
        if total % n:
            return -1
        target = total // n
        ans = bal = 0
        for m in machines:
            diff = m - target
            bal += diff
            ans = max(ans, abs(bal), abs(diff))
        return ans

