class Solution {
public:
    int findMinMoves(vector<int>& machines) {
        long long sum = 0;
        for (int x : machines) sum += x;
        int n = machines.size();
        if (sum % n) return -1;
        int target = sum / n;
        long long bal = 0;
        int ans = 0;
        for (int m : machines) {
            int diff = m - target;
            bal += diff;
            ans = max({ans, (int)abs(bal), abs(diff)});
        }
        return ans;
    }
};
